={{(() => {
  const msgType = $('Meta').item.json.body.data.messageType;

  switch (msgType) {
    case 'audioMessage':
      return 'audio';
    case 'extendedTextMessage':
      return 'text';
    case 'conversation':
      return 'text';
    case 'imageMessage':
      return 'image';
    case 'documentMessage':
      return 'doc';
    case 'stickerMessage':
      return 'image';
    default:
      return 'unknown'; // Caso não corresponda a nenhum tipo
  }
})()}}

parameters.jsCode:
return $json._embedded.leads.map(lead => {
  const customFields = lead.custom_fields_values;

  // Find the "Parar bot" field
  const checkboxField = customFields?.find(field => field.field_name === 'PARAR IA');

  // Determine the checkbox state
  const isCheckboxActive = checkboxField?.values?.[0]?.value === true || false;

  // Return the lead with an added field for the checkbox status
  return {
    json: {
      id: lead.id,
      name: lead.name,
      checkboxState: isCheckboxActive
    }
  };
});

